import threading
from queue import Queue
import time
import random

class ATM:
    def __init__(self, atm_id, balance=1000):
        self.atm_id = atm_id
        self.balance = balance
        self.lock = threading.Lock()

    def withdraw(self, amount):
        with self.lock:
            if amount > self.balance:
                return False
            self.balance -= amount
            return True

    def deposit(self, amount):
        with self.lock:
            self.balance += amount
            return True

class TransactionManager:
    def __init__(self):
        self.atms = {}
        self.queue = Queue()
        self.lock = threading.Lock()

    def add_atm(self, atm_id, atm):
        with self.lock:
            self.atms[atm_id] = atm

    def process_transaction(self, atm_id, transaction_type, amount):
        with self.lock:
            if atm_id not in self.atms:
                return False
            atm = self.atms[atm_id]
            if transaction_type == 'withdraw':
                return atm.withdraw(amount)
            elif transaction_type == 'deposit':
                return atm.deposit(amount)
            return False

    def start_processing(self):
        while True:
            atm_id, transaction_type, amount = self.queue.get()
            result = self.process_transaction(atm_id, transaction_type, amount)
            print(f'ATM {atm_id}: {transaction_type} {amount} - {"Success" if result else "Failed"}')
            self.queue.task_done()

def main():
    manager = TransactionManager()
    atm1 = ATM('ATM1')
    atm2 = ATM('ATM2')
    manager.add_atm('ATM1', atm1)
    manager.add_atm('ATM2', atm2)

    processing_thread = threading.Thread(target=manager.start_processing)
    processing_thread.daemon = True
    processing_thread.start()

    for _ in range(10):
        atm_id = random.choice(['ATM1', 'ATM2'])
        transaction_type = random.choice(['withdraw', 'deposit'])
        amount = random.randint(1, 100)
        manager.queue.put((atm_id, transaction_type, amount))
        time.sleep(0.1)

    manager.queue.join()

if __name__ == '__main__':
    main()

