import threading
from queue import Queue
from enum import Enum
import time
import random

class TransactionStatus(Enum):
    SUCCESS = 1
    FAILURE = 2
    PENDING = 3

class TransactionType(Enum):
    WITHDRAWAL = 1
    DEPOSIT = 2
    CHECK_BALANCE = 3

class ATM:
    def __init__(self, atm_id, balance=1000):
        self.atm_id = atm_id
        self.balance = balance
        self.lock = threading.Lock()

    def withdraw(self, amount):
        with self.lock:
            if amount > self.balance:
                return TransactionStatus.FAILURE
            self.balance -= amount
            return TransactionStatus.SUCCESS

    def deposit(self, amount):
        with self.lock:
            self.balance += amount
            return TransactionStatus.SUCCESS

    def check_balance(self):
        with self.lock:
            return self.balance

class Transaction:
    def __init__(self, atm, transaction_type, amount=0):
        self.atm = atm
        self.transaction_type = transaction_type
        self.amount = amount
        self.status = TransactionStatus.PENDING

    def process(self):
        if self.transaction_type == TransactionType.WITHDRAWAL:
            self.status = self.atm.withdraw(self.amount)
        elif self.transaction_type == TransactionType.DEPOSIT:
            self.status = self.atm.deposit(self.amount)
        elif self.transaction_type == TransactionType.CHECK_BALANCE:
            self.status = TransactionStatus.SUCCESS
            self.amount = self.atm.check_balance()

class TransactionManager:
    def __init__(self):
        self.queue = Queue()
        self.lock = threading.Lock()

    def add_transaction(self, transaction):
        with self.lock:
            self.queue.put(transaction)

    def process_transactions(self):
        while True:
            transaction = self.queue.get()
            transaction.process()
            self.queue.task_done()

class FraudDetector:
    def __init__(self):
        self.suspicious_atms = set()

    def detect_fraud(self, atm, transaction):
        if atm.atm_id in self.suspicious_atms:
            return True
        if transaction.transaction_type == TransactionType.WITHDRAWAL and transaction.amount > 1000:
            self.suspicious_atms.add(atm.atm_id)
            return True
        return False

def main():
    atms = [ATM(i) for i in range(10)]
    transaction_manager = TransactionManager()
    fraud_detector = FraudDetector()

    for _ in range(100):
        atm = random.choice(atms)
        transaction_type = random.choice(list(TransactionType))
        amount = random.randint(1, 1000)
        transaction = Transaction(atm, transaction_type, amount)
        if fraud_detector.detect_fraud(atm, transaction):
            print(f"Fraud detected at ATM {atm.atm_id}")
            continue
        transaction_manager.add_transaction(transaction)

    for _ in range(10):
        threading.Thread(target=transaction_manager.process_transactions).start()

    transaction_manager.queue.join()

    for atm in atms:
        print(f"ATM {atm.atm_id} balance: {atm.check_balance()}")

if __name__ == "__main__":
    main()

