import time
from enum import Enum

class TransactionStatus(Enum):
    SUCCESS = 1
    FAILURE = 2
    PENDING = 3

class ATM:
    def __init__(self, atm_id, balance):
        self.atm_id = atm_id
        self.balance = balance
        self.lock = threading.Lock()

    def withdraw(self, amount):
        with self.lock:
            if amount > self.balance:
                return TransactionStatus.FAILURE
            self.balance -= amount
            return TransactionStatus.SUCCESS

    def deposit(self, amount):
        with self.lock:
            self.balance += amount
            return TransactionStatus.SUCCESS

class TransactionManager:
    def __init__(self):
        self.atms = {}
        self.queue = Queue()
        self.lock = threading.Lock()

    def add_atm(self, atm_id, balance):
        with self.lock:
            self.atms[atm_id] = ATM(atm_id, balance)

    def process_transaction(self, atm_id, transaction_type, amount):
        with self.lock:
            if atm_id not in self.atms:
                return TransactionStatus.FAILURE
            atm = self.atms[atm_id]
            if transaction_type == 'withdraw':
                return atm.withdraw(amount)
            elif transaction_type == 'deposit':
                return atm.deposit(amount)
            else:
                return TransactionStatus.FAILURE

    def start_transaction(self, atm_id, transaction_type, amount):
        self.queue.put((atm_id, transaction_type, amount))
        threading.Thread(target=self.process_transaction_thread).start()

    def process_transaction_thread(self):
        while not self.queue.empty():
            atm_id, transaction_type, amount = self.queue.get()
            status = self.process_transaction(atm_id, transaction_type, amount)
            logging.info(f'Transaction {transaction_type} of {amount} on ATM {atm_id} {status.name}')

class FraudDetector:
    def __init__(self):
        self.attempts = {}

    def check_fraud(self, atm_id):
        if atm_id not in self.attempts:
            self.attempts[atm_id] = 0
        self.attempts[atm_id] += 1
        if self.attempts[atm_id] > 3:
            return True
        return False

class Controller:
