            if atm_id in self.atms:
                del self.atms[atm_id]

    def get_atm(self, atm_id):
        with self.lock:
            return self.atms.get(atm_id)

    def transfer(self, from_atm_id, to_atm_id, amount):
        with self.lock:
            from_atm = self.atms.get(from_atm_id)
            to_atm = self.atms.get(to_atm_id)
            if from_atm and to_atm:
                from_atm.withdraw(amount)
                to_atm.deposit(amount)
                return True
            return False


