        self.atm_id = atm_id
        self.balance = balance
        self.lock = threading.Lock()

    def withdraw(self, amount):
        with self.lock:
            if amount > self.balance:
                return False
            time.sleep(random.uniform(0.1, 0.5))  # simulate transaction time
            self.balance -= amount
            return True

    def deposit(self, amount):
        with self.lock:
            time.sleep(random.uniform(0.1, 0.5))  # simulate transaction time
            self.balance += amount
            return True

class ATMNetwork:
    def __init__(self):
        self.atms = {}
        self.queue = Queue()
        self.lock = threading.Lock()

    def add_atm(self, atm_id, balance=1000):
        with self.lock:
            self.atms[atm_id] = ATM(atm_id, balance)

    def remove_atm(self, atm_id):
        with self.lock:
            if atm_id in self.atms:
                del self.atms[atm_id]

    def process_transaction(self, atm_id, transaction_type, amount):
        with self.lock:
            if atm_id in self.atms:
                atm = self.atms[atm_id]
                if transaction_type == 'withdraw':
                    return atm.withdraw(amount)
                elif transaction_type == 'deposit':
                    return atm.deposit(amount)
            return False

    def start_transaction_monitor(self):
        while True:
            atm_id, transaction_type, amount = self.queue.get()
            result = self.process_transaction(atm_id, transaction_type, amount)
            print(f'ATM {atm_id}: {transaction_type} {amount} - {"Success" if result else "Failed"}')
            self.queue.task_done()

