import threading
from typing import Dict, List

class Account:
    def __init__(self, account_number: str, balance: float):
        self.account_number = account_number
        self.balance = balance
        self.lock = threading.Lock()

    def deposit(self, amount: float):
        with self.lock:
            self.balance += amount

    def withdraw(self, amount: float):
        with self.lock:
            if self.balance >= amount:
                self.balance -= amount
                return True
            else:
                return False

class ATM:
    def __init__(self, atm_id: str):
        self.atm_id = atm_id
        self.lock = threading.Lock()

    def transaction(self, account: Account, amount: float, transaction_type: str):
        with self.lock:
            if transaction_type == 'deposit':
                account.deposit(amount)
                return True
            elif transaction_type == 'withdrawal':
                if account.withdraw(amount):
                    return True
                else:
                    return False
            else:
                return False

class ATMNetwork:
    def __init__(self):
        self.accounts: Dict[str, Account] = {}
        self.atms: Dict[str, ATM] = {}
        self.lock = threading.Lock()

    def add_account(self, account_number: str, balance: float):
        with self.lock:
            self.accounts[account_number] = Account(account_number, balance)

    def add_atm(self, atm_id: str):
        with self.lock:
            self.atms[atm_id] = ATM(atm_id)

    def get_account(self, account_number: str):
        with self.lock:
            return self.accounts.get(account_number)

    def get_atm(self, atm_id: str):
        with self.lock:
            return self.atms.get(atm_id)

    def transaction(self, atm_id: str, account_number: str, amount: float, transaction_type: str):
        with self.lock:
            atm = self.get_atm(atm_id)
            account = self.get_account(account_number)
            if atm and account:
                return atm.transaction(account, amount, transaction_type)
            else:
                return False

def main():
    atm_network = ATMNetwork()
    atm_network.add_atm('ATM1')
    atm_network.add_atm('ATM2')
    atm_network.add_account('12345', 1000.0)
    atm_network.add_account('67890', 500.0)

    atm1 = atm_network.get_atm('ATM1')
    atm2 = atm_network.get_atm('ATM2')
    account1 = atm_network.get_account('12345')
    account2 = atm_network.get_account('67890')

    threads = []
    thread1 = threading.Thread(target=atm1.transaction, args=(account1, 500.0, 'withdrawal'))
    thread2 = threading.Thread(target=atm2.transaction, args=(account2, 200.0, 'deposit'))
    threads.append(thread1)
    threads.append(thread2)
    thread1.start()
    thread2.start()

    for thread in threads:
        thread.join()

    print('Account 1 balance:', account1.balance)
    print('Account 2 balance:', account2.balance)

if __name__ == '__main__':
    main()

