class ATMController:
    def __init__(self):
        self.accounts = {}
        self.lock = threading.Lock()
        self.queue = Queue()

    def create_account(self, account_number, balance):
        with self.lock:
            if account_number not in self.accounts:
                self.accounts[account_number] = balance
                print(f"Account {account_number} created with balance {balance}")
            else:
                print(f"Account {account_number} already exists")

    def deposit(self, account_number, amount):
        with self.lock:
            if account_number in self.accounts:
                self.accounts[account_number] += amount
                print(f"Deposited {amount} into account {account_number}")
            else:
                print(f"Account {account_number} does not exist")

    def withdraw(self, account_number, amount):
        with self.lock:
            if account_number in self.accounts:
                if self.accounts[account_number] >= amount:
                    self.accounts[account_number] -= amount
                    print(f"Withdrew {amount} from account {account_number}")
                else:
                    print(f"Insufficient balance in account {account_number}")
            else:
                print(f"Account {account_number} does not exist")

    def transfer(self, from_account, to_account, amount):
        with self.lock:
            if from_account in self.accounts and to_account in self.accounts:
                if self.accounts[from_account] >= amount:
                    self.accounts[from_account] -= amount
                    self.accounts[to_account] += amount
                    print(f"Transferred {amount} from account {from_account} to account {to_account}")
                else:
                    print(f"Insufficient balance in account {from_account}")
            else:
                print(f"One or both accounts do not exist")

    def process_transactions(self):
        while True:
            transaction = self.queue.get()
            if transaction['type'] == 'deposit':
                self.deposit(transaction['account'], transaction['amount'])
            elif transaction['type'] == 'withdraw':
                self.withdraw(transaction['account'], transaction['amount'])
            elif transaction['type'] == 'transfer':
                self.transfer(transaction['from_account'], transaction['to_account'], transaction['amount'])
            self.queue.task_done()

    def start(self):
        for _ in range(5):
            threading.Thread(target=self.process_transactions, daemon=True).start()

    def add_transaction(self, transaction):
        self.queue.put(transaction)

