        with self.lock:
            if atm_id not in self.atms:
                self.atms[atm_id] = {"status": "available", "balance": 0}
                self.logger.info(f"ATM {atm_id} added")

    def remove_atm(self, atm_id):
        with self.lock:
            if atm_id in self.atms:
                del self.atms[atm_id]
                self.logger.info(f"ATM {atm_id} removed")

    def deposit(self, atm_id, amount):
        with self.lock:
            if atm_id in self.atms and self.atms[atm_id]["status"] == "available":
                self.atms[atm_id]["balance"] += amount
                self.logger.info(f"Deposited {amount} into ATM {atm_id}")
                return True
            else:
                self.logger.error(f"Failed to deposit into ATM {atm_id}")
                return False

    def withdraw(self, atm_id, amount):
        with self.lock:
            if atm_id in self.atms and self.atms[atm_id]["status"] == "available" and self.atms[atm_id]["balance"] >= amount:
                self.atms[atm_id]["balance"] -= amount
                self.logger.info(f"Withdrew {amount} from ATM {atm_id}")
                return True
            else:
                self.logger.error(f"Failed to withdraw from ATM {atm_id}")
                return False

    def process_transaction(self, transaction):
        self.queue.put(transaction)
        self.logger.info(f"Transaction {transaction} added to queue")

    def start_processing(self):
        while True:
            transaction = self.queue.get()
            if transaction["type"] == "deposit":
                self.deposit(transaction["atm_id"], transaction["amount"])
            elif transaction["type"] == "withdrawal":
                self.withdraw(transaction["atm_id"], transaction["amount"])
            self.queue.task_done()

