class ATM:
    def __init__(self, location):
        self.location = location
        self.balance = 0
        self.is_online = False
        self.lock = Lock()

    def connect(self):
        self.lock.acquire()
        try:
            if not self.is_online:
                self.is_online = True
                print(f"ATM at {self.location} is now online.")
            else:
                print(f"ATM at {self.location} is already online.")
        finally:
            self.lock.release()

    def disconnect(self):
        self.lock.acquire()
        try:
            if self.is_online:
                self.is_online = False
                print(f"ATM at {self.location} is now offline.")
            else:
                print(f"ATM at {self.location} is already offline.")
        finally:
            self.lock.release()

    def deposit(self, amount):
        self.lock.acquire()
        try:
            if self.is_online:
                self.balance += amount
                print(f"Deposited ${amount} at {self.location}. Current balance: ${self.balance}")
            else:
                print(f"ATM at {self.location} is offline. Cannot deposit.")
        except Exception as e:
            print(f"Error depositing at {self.location}: {str(e)}")
        finally:
            self.lock.release()

    def withdraw(self, amount):
        self.lock.acquire()
        try:
            if self.is_online:
                if self.balance >= amount:
                    self.balance -= amount
                    print(f"Withdrew ${amount} at {self.location}. Current balance: ${self.balance}")
                else:
                    print(f"Insufficient balance at {self.location}.")
            else:
                print(f"ATM at {self.location} is offline. Cannot withdraw.")
        except Exception as e:
            print(f"Error withdrawing at {self.location}: {str(e)}")
        finally:
            self.lock.release()

