class ATM:
    def __init__(self):
        self.accounts = {}

    def create_account(self, account_number, pin, balance=0):
        self.accounts[account_number] = {'pin': pin, 'balance': balance}

    def check_balance(self, account_number, pin):
        if account_number in self.accounts and self.accounts[account_number]['pin'] == pin:
            return self.accounts[account_number]['balance']
        else:
            return None

    def withdraw(self, account_number, pin, amount):
        if account_number in self.accounts and self.accounts[account_number]['pin'] == pin:
            if self.accounts[account_number]['balance'] >= amount:
                self.accounts[account_number]['balance'] -= amount
                return True
            else:
                return False
        else:
            return None

    def deposit(self, account_number, pin, amount):
        if account_number in self.accounts and self.accounts[account_number]['pin'] == pin:
            self.accounts[account_number]['balance'] += amount
            return True
        else:
            return None

